@Service
public class ProductIndexService {

    private final RestHighLevelClient client;
    private final ObjectMapper mapper;
    private final String productsIndex;

    public ProductIndexService(RestHighLevelClient client, ObjectMapper mapper,
                               @Value("${elasticsearch.index.products:products}") String productsIndex) {
        this.client = client;
        this.mapper = mapper;
        this.productsIndex = productsIndex;
    }

    public String getProductsIndex() {
        return productsIndex;
    }

    public void ensureIndex() throws IOException {
        boolean exists = client.indices().exists(new GetIndexRequest(productsIndex), RequestOptions.DEFAULT);
        if (exists) return;

        CreateIndexRequest req = new CreateIndexRequest(productsIndex);
        req.settings(Settings.builder()
                .put("index.number_of_shards", 1)
                .put("index.number_of_replicas", 0)
                .put("analysis.analyzer.folded.type", "custom")
                .put("analysis.analyzer.folded.tokenizer", "standard")
                .putList("analysis.analyzer.folded.filter", Arrays.asList("lowercase", "asciifolding"))
        );

        String mappingJson = "{\n" +
                "  \"dynamic\": true,\n" +
                "  \"properties\": {\n" +
                "    \"sku\": {\"type\":\"keyword\"},\n" +
                "    \"name\": {\"type\":\"text\",\"analyzer\":\"folded\",\"fields\":{\"keyword\":{\"type\":\"keyword\",\"ignore_above\":256}}},\n" +
                "    \"description\": {\"type\":\"text\",\"analyzer\":\"folded\"},\n" +
                "    \"brand\": {\"type\":\"keyword\"},\n" +
                "    \"categories\": {\"type\":\"keyword\"},\n" +
                "    \"tags\": {\"type\":\"keyword\"},\n" +
                "    \"price\": {\"type\":\"double\"},\n" +
                "    \"currency\": {\"type\":\"keyword\"},\n" +
                "    \"inStock\": {\"type\":\"boolean\"},\n" +
                "    \"rating\": {\"type\":\"double\"},\n" +
                "    \"reviewCount\": {\"type\":\"integer\"},\n" +
                "    \"attributes\": {\"type\":\"object\",\"dynamic\":true}\n" +
                "  }\n" +
                "}";
        req.mapping(mappingJson, XContentType.JSON);
        client.indices().create(req, RequestOptions.DEFAULT);
    }

    public void putMapping(String mappingJson) throws IOException {
        PutMappingRequest pm = new PutMappingRequest(productsIndex);
        pm.source(mappingJson, XContentType.JSON);
        client.indices().putMapping(pm, RequestOptions.DEFAULT);
    }

    public void deleteIndexIfExists() throws IOException {
        boolean exists = client.indices().exists(new GetIndexRequest(productsIndex), RequestOptions.DEFAULT);
        if (!exists) return;
        try {
            client.indices().delete(new DeleteIndexRequest(productsIndex), RequestOptions.DEFAULT);
        } catch (ElasticsearchStatusException e) {
            // ignore
        }
    }

    public void index(Product product) throws IOException {
        ensureIndex();
        Map<String, Object> src = mapper.convertValue(product, new TypeReference<Map<String, Object>>() {});
        IndexRequest req = new IndexRequest(productsIndex)
                .id(product.getId())
                .source(src)
                .setRefreshPolicy(WriteRequest.RefreshPolicy.WAIT_UNTIL);
        client.index(req, RequestOptions.DEFAULT);
    }

    public BulkResponse bulkIndex(List<Product> products) throws IOException {
        ensureIndex();
        BulkRequest bulk = new BulkRequest().setRefreshPolicy(WriteRequest.RefreshPolicy.WAIT_UNTIL);
        for (Product p : products) {
            Map<String, Object> src = mapper.convertValue(p, new TypeReference<Map<String, Object>>() {});
            bulk.add(new IndexRequest(productsIndex).id(p.getId()).source(src));
        }
        return client.bulk(bulk, RequestOptions.DEFAULT);
    }
}
package com.example.search.service;

import com.example.search.dto.ProductSearchRequest;
import com.example.search.dto.ProductSearchResponse;
import com.example.search.model.Product;
import com.example.search.model.SearchQueryEvent;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import java.io.IOException;
import java.time.Instant;
import java.util.*;
import java.util.stream.Collectors;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.action.support.WriteRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.MultiMatchQueryBuilder;
import org.elasticsearch.index.query.Operator;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.SearchHit;
import org.elasticsearch.search.aggregations.Aggregation;
import org.elasticsearch.search.aggregations.Aggregations;
import org.elasticsearch.search.aggregations.bucket.filter.Filter;
import org.elasticsearch.search.aggregations.bucket.range.Range;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.sort.SortBuilders;
import org.elasticsearch.search.sort.SortOrder;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

@Service
public class ProductSearchService {

    private final RestHighLevelClient client;
    private final ObjectMapper mapper;
    private final ProductIndexService indexService;
    private final String queriesIndex;

    public ProductSearchService(RestHighLevelClient client, ObjectMapper mapper, ProductIndexService indexService,
                                @Value("${elasticsearch.index.queries:search_queries}") String queriesIndex) {
        this.client = client;
        this.mapper = mapper;
        this.indexService = indexService;
        this.queriesIndex = queriesIndex;
    }

    public ProductSearchResponse search(ProductSearchRequest req, String customerId, String sessionId, String userAgent, String ip) throws IOException {
        indexService.ensureIndex();
        ensureQueriesIndex();

        int page = req.getPage() == null ? 0 : Math.max(0, req.getPage());
        int size = req.getSize() == null ? 20 : Math.min(200, Math.max(1, req.getSize()));
        int from = page * size;

        BoolQueryBuilder qb = QueryBuilders.boolQuery();

        String q = req.getQ();
        if (q == null || q.trim().isEmpty()) {
            qb.must(QueryBuilders.matchAllQuery());
        } else {
            MultiMatchQueryBuilder mm = QueryBuilders.multiMatchQuery(q, "name^4", "description^1", "tags^2", "brand^2", "categories^2")
                    .type(MultiMatchQueryBuilder.Type.BEST_FIELDS)
                    .operator(Operator.AND)
                    .fuzziness("AUTO");
            qb.must(mm);
        }

        if (req.getCategories() != null && !req.getCategories().isEmpty()) {
            qb.filter(QueryBuilders.termsQuery("categories", req.getCategories()));
        }
        if (req.getBrands() != null && !req.getBrands().isEmpty()) {
            qb.filter(QueryBuilders.termsQuery("brand", req.getBrands()));
        }
        if (req.getInStock() != null) {
            qb.filter(QueryBuilders.termQuery("inStock", req.getInStock()));
        }
        if (req.getPriceMin() != null || req.getPriceMax() != null) {
            var range = QueryBuilders.rangeQuery("price");
            if (req.getPriceMin() != null) range.gte(req.getPriceMin());
            if (req.getPriceMax() != null) range.lte(req.getPriceMax());
            qb.filter(range);
        }

        if (req.getAttributes() != null && !req.getAttributes().isEmpty()) {
            for (Map.Entry<String, List<String>> e : req.getAttributes().entrySet()) {
                if (e.getKey() == null || e.getKey().isBlank()) continue;
                if (e.getValue() == null || e.getValue().isEmpty()) continue;
                String field = "attributes." + e.getKey();
                qb.filter(QueryBuilders.termsQuery(field, e.getValue()));
            }
        }

        SearchSourceBuilder ssb = new SearchSourceBuilder()
                .query(qb)
                .from(from)
                .size(size)
                .trackTotalHits(true);

        applySort(ssb, req.getSort());

        ssb.aggregation(org.elasticsearch.search.aggregations.AggregationBuilders.terms("facet_brand").field("brand").size(50));
        ssb.aggregation(org.elasticsearch.search.aggregations.AggregationBuilders.terms("facet_category").field("categories").size(50));
        ssb.aggregation(org.elasticsearch.search.aggregations.AggregationBuilders.filter("facet_inStock", QueryBuilders.termQuery("inStock", true)));
        ssb.aggregation(org.elasticsearch.search.aggregations.AggregationBuilders.range("facet_price")
                .field("price")
                .addUnboundedTo(25)
                .addRange(25, 50)
                .addRange(50, 100)
                .addRange(100, 250)
                .addRange(250, 500)
                .addUnboundedFrom(500)
        );

        SearchRequest sr = new SearchRequest(indexService.getProductsIndex());
        sr.source(ssb);

        SearchResponse resp = client.search(sr, RequestOptions.DEFAULT);

        List<Product> items = Arrays.stream(resp.getHits().getHits())
                .map(this::hitToProduct)
                .collect(Collectors.toList());

        long total = resp.getHits().getTotalHits() == null ? items.size() : resp.getHits().getTotalHits().value;
        Map<String, Object> facets = parseFacets(resp.getAggregations());

        SearchQueryEvent event = new SearchQueryEvent();
        event.setId(UUID.randomUUID().toString());
        event.setQuery(q);
        event.setTimestamp(Instant.now());
        event.setCustomerId(customerId);
        event.setSessionId(sessionId);
        event.setPage(page);
        event.setSize(size);
        event.setAppliedFilters(buildAppliedFilters(req));
        event.setTotalHits(total);
        event.setSort(req.getSort());
        event.setUserAgent(userAgent);
        event.setIp(ip);
        indexQueryEvent(event);

        return new ProductSearchResponse(items, total, page, size, facets);
    }

    private void applySort(SearchSourceBuilder ssb, String sort) {
        if (sort == null || sort.isBlank() || "relevance".equalsIgnoreCase(sort)) return;

        switch (sort.toLowerCase(Locale.ROOT)) {
            case "price_asc":
                ssb.sort(SortBuilders.fieldSort("price").order(SortOrder.ASC).missing("_last"));
                break;
            case "price_desc":
                ssb.sort(SortBuilders.fieldSort("price").order(SortOrder.DESC).missing("_last"));
                break;
            case "rating_desc":
                ssb.sort(SortBuilders.fieldSort("rating").order(SortOrder.DESC).missing("_last"));
                break;
            case "name_asc":
                ssb.sort(SortBuilders.fieldSort("name.keyword").order(SortOrder.ASC).missing("_last"));
                break;
            default:
                break;
        }
    }

    private Map<String, Object> buildAppliedFilters(ProductSearchRequest req) {
        Map<String, Object> m = new LinkedHashMap<>();
        if (req.getCategories() != null && !req.getCategories().isEmpty()) m.put("categories", req.getCategories());
        if (req.getBrands() != null && !req.getBrands().isEmpty()) m.put("brands", req.getBrands());
        if (req.getInStock() != null) m.put("inStock", req.getInStock());
        if (req.getPriceMin() != null || req.getPriceMax() != null) {
            Map<String, Object> p = new LinkedHashMap<>();
            if (req.getPriceMin() != null) p.put("min", req.getPriceMin());
            if (req.getPriceMax() != null) p.put("max", req.getPriceMax());
            m.put("price", p);
        }
        if (req.getAttributes() != null && !req.getAttributes().isEmpty()) m.put("attributes", req.getAttributes());
        return m;
    }

    private Product hitToProduct(SearchHit hit) {
        Map<String, Object> src = hit.getSourceAsMap();
        Product p = mapper.convertValue(src, Product.class);
        if (p.getId() == null) p.setId(hit.getId());
        return p;
    }

    private Map<String, Object> parseFacets(Aggregations aggs) {
        Map<String, Object> facets = new LinkedHashMap<>();
        if (aggs == null) return facets;

        Aggregation brandAgg = aggs.get("facet_brand");
        if (brandAgg instanceof Terms) {
            List<Map<String, Object>> buckets = ((Terms) brandAgg).getBuckets().stream().map(b -> {
                Map<String, Object> o = new LinkedHashMap<>();
                o.put("key", b.getKeyAsString());
                o.put("count", b.getDocCount());
                return o;
            }).collect(Collectors.toList());
            facets.put("brand", buckets);
        }

        Aggregation catAgg = aggs.get("facet_category");
        if (catAgg instanceof Terms) {
            List<Map<String, Object>> buckets = ((Terms) catAgg).getBuckets().stream().map(b -> {
                Map<String, Object> o = new LinkedHashMap<>();
                o.put("key", b.getKeyAsString());
                o.put("count", b.getDocCount());
                return o;
            }).collect(Collectors.toList());
            facets.put("categories", buckets);
        }

        Aggregation inStockAgg = aggs.get("facet_inStock");
        if (inStockAgg instanceof Filter) {
            Map<String, Object> o = new LinkedHashMap<>();
            o.put("count", ((Filter) inStockAgg).getDocCount());
            facets.put("inStock", o);
        }

        Aggregation priceAgg = aggs.get("facet_price");
        if (priceAgg instanceof Range) {
            List<Map<String, Object>> buckets = ((Range) priceAgg).getBuckets().stream().map(b -> {
                Map<String, Object> o = new LinkedHashMap<>();
                o.put("key", b.getKeyAsString());
                o.put("from", b.getFrom());
                o.put("to", b.getTo());
                o.put("count", b.getDocCount());
                return o;
            }).collect(Collectors.toList());
            facets.put("price", buckets);
        }

        return facets;
    }

    private void ensureQueriesIndex() throws IOException {
        boolean exists = client.indices().exists(new org.elasticsearch.client.indices.GetIndexRequest(queriesIndex), RequestOptions.DEFAULT);
        if (exists) return;

        org.elasticsearch.client.indices.CreateIndexRequest req = new org.elasticsearch.client.indices.CreateIndexRequest(queriesIndex);
        req.settings(org.elasticsearch.common.settings.Settings.builder()
                .put("index.number_of_shards", 1)
                .put("index.number_of_replicas", 0)
        );

        String mappingJson = "{\n" +
                "  \"dynamic\": true,\n" +
                "  \"properties\": {\n" +
                "    \"query\": {\"type\":\"text\"},\n" +
                "    \"timestamp\": {\"type\":\"date\"},\n" +
                "    \"customerId\": {\"type\":\"keyword\"},\n" +
                "    \"sessionId\": {\"type\":\"keyword\"},\n" +
                "    \"page\": {\"type\":\"integer\"},\n" +
                "    \"size\": {\"type\":\"integer\"},\n" +
                "    \"totalHits\": {\"type\":\"long\"},\n" +
                "    \"sort\": {\"type\":\"keyword\"},\n" +
                "    \"userAgent\": {\"type\":\"keyword\",\"ignore_above\":1024},\n" +
                "    \"ip\": {\"type\":\"ip\"},\n" +
                "    \"appliedFilters\": {\"type\":\"object\",\"dynamic\":true}\n" +
                "  }\n" +
                "}";
        req.mapping(mappingJson, org.elasticsearch.common.xcontent.XContentType.JSON);
        client.indices().create(req, RequestOptions.DEFAULT);
    }

    private void indexQueryEvent(SearchQueryEvent event) throws IOException {
        Map<String, Object> src = mapper.convertValue(event, new TypeReference<Map<String, Object>>() {});
        IndexRequest ir = new IndexRequest(queriesIndex)
                .id(event.getId())
                .source(src)
                .setRefreshPolicy(WriteRequest.RefreshPolicy.NONE);
        client.index(ir, RequestOptions.DEFAULT);
    }
}
package com.example.search.controller;

import com.example.search.model.Product;
import com.example.search.service.ProductIndexService;
import java.io.IOException;
import java.util.List;
import org.elasticsearch.action.bulk.BulkResponse;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/products")
public class ProductController {

    private final ProductIndexService indexService;

    public ProductController(ProductIndexService indexService) {
        this.indexService = indexService;
    }

    @PostMapping("/index")
    public ResponseEntity<Void> index(@RequestBody Product product) throws IOException {
        if (product.getId() == null || product.getId().isBlank()) {
            return ResponseEntity.status(HttpStatus.BAD_REQUEST).build();
        }
        indexService.index(product);
        return ResponseEntity.status(HttpStatus.CREATED).build();
    }

    @PostMapping("/bulk")
    public ResponseEntity<String> bulk(@RequestBody List<Product> products) throws IOException {
        BulkResponse resp = indexService.bulkIndex(products);
        if (resp.hasFailures()) {
            return ResponseEntity.status(HttpStatus.MULTI_STATUS).body(resp.buildFailureMessage());
        }
        return ResponseEntity.ok("OK");
    }
}
