import com.example.search.dto.ProductSearchResponse;
import com.example.search.service.ProductSearchService;
import java.io.IOException;
import org.springframework.web.bind.annotation.*;

import jakarta.servlet.http.HttpServletRequest;

@RestController
@RequestMapping("/api/search")
public class SearchController {

    private final ProductSearchService searchService;

    public SearchController(ProductSearchService searchService) {
        this.searchService = searchService;
    }

    @PostMapping("/products")
    public ProductSearchResponse search(@RequestBody ProductSearchRequest req,
                                        @RequestHeader(value = "X-Customer-Id", required = false) String customerId,
                                        @RequestHeader(value = "X-Session-Id", required = false) String sessionId,
                                        HttpServletRequest servletRequest) throws IOException {

        String ua = servletRequest.getHeader("User-Agent");
        String ip = servletRequest.getRemoteAddr();
        return searchService.search(req, customerId, sessionId, ua, ip);
    }
}
package com.example.search.controller;

import com.example.search.service.ProductIndexService;
import java.io.IOException;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/admin")
public class AdminController {

    private final ProductIndexService indexService;

    public AdminController(ProductIndexService indexService) {
        this.indexService = indexService;
    }

    @PostMapping("/indices/products/ensure")
    public ResponseEntity<String> ensureProducts() throws IOException {
        indexService.ensureIndex();
        return ResponseEntity.ok("OK");
    }

    @DeleteMapping("/indices/products")
    public ResponseEntity<String> deleteProducts() throws IOException {
        indexService.deleteIndexIfExists();
        return ResponseEntity.ok("OK");
    }
}
package com.example.search.config;

import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.datatype.jsr310.JavaTimeModule;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

@Configuration
public class JacksonConfig {
    @Bean
    public ObjectMapper objectMapper() {
        ObjectMapper om = new ObjectMapper();
        om.registerModule(new JavaTimeModule());
        return om;
    }
}
package com.example.search.error;

import java.io.IOException;
import org.elasticsearch.ElasticsearchException;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestControllerAdvice
public class GlobalExceptionHandler {

    @ExceptionHandler({ElasticsearchException.class, IOException.class})
    public ResponseEntity<String> handleEs(Exception e) {
        return ResponseEntity.status(HttpStatus.BAD_GATEWAY).body(e.getMessage());
    }

    @ExceptionHandler(IllegalArgumentException.class)
    public ResponseEntity<String> handleBad(IllegalArgumentException e) {
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(e.getMessage());
    }
}
package com.example.search;

import org.springframework.boot.CommandLineRunner;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import com.example.search.service.ProductIndexService;

@Configuration
public class StartupInit {

    @Bean
    public CommandLineRunner init(ProductIndexService indexService) {
        return args -> indexService.ensureIndex();
    }
}
package com.example.search.util;

import java.util.LinkedHashMap;
import java.util.Map;

public final class Maps {
    private Maps() {}

    public static Map<String, Object> of(Object... kv) {
        Map<String, Object> m = new LinkedHashMap<>();
        for (int i = 0; i + 1 < kv.length; i += 2) {
            m.put(String.valueOf(kv[i]), kv[i + 1]);
        }
        return m;
    }
}